class Solution:
    def beautifulSubarrays(self, nums):
        n = len(nums)
        count = 0
        for i in range(n):
            for j in range(i, n):
                sub = nums[i:j + 1]
                ok = True
                for bit in range(21):
                    c = sum(1 for x in sub if (x >> bit) & 1)
                    if c % 2 != 0:
                        ok = False
                        break
                if ok:
                    count += 1
        return count

