var beautifulSubarrays = function(nums) {
    const cnt = new Map();
    cnt.set(0, 1);
    let prefix = 0;
    let total = 0;
    for (const v of nums) {
        prefix ^= v;
        total += cnt.get(prefix) || 0;
        cnt.set(prefix, (cnt.get(prefix) || 0) + 1);
    }
    return total;
};
